```class Solution {
    public int countEven(int num) {
        int count = 0;
        for (int i = num; i >= 10; i--) {
            int digitSum = 0;
            while (i != 0) {
                digitSum += i % 10;
                i /= 10;
            }
            if (digitSum % 2 == 0) {
                count++;
            }
        }
        return count;
    }
}
```

